def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Identify the main subject (airport) - typically the one with airport-related predicates
    main_subject = None
    airport_predicates = {"cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel",
                         "icaoLocationIdentifier", "iataLocationIdentifier", "runwaySurfaceType"}

    for subject, triples_list in subject_map.items():
        if any(p in airport_predicates for p, _ in triples_list):
            main_subject = subject
            break

    if not main_subject and subject_map:
        main_subject = list(subject_map.keys())[0]

    if not main_subject:
        return "."

    # Build a single complex sentence with proper relationships
    sentence_parts = [main_subject]
    location_info = None
    country_info = None
    language_info = None
    other_clauses = []

    # Process all triples to build relationships
    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if predicate == "cityServed":
                sentence_parts.append(f"serves the city of {obj}")
            elif predicate == "location":
                location_info = obj
            elif predicate == "country":
                country_info = obj
            elif predicate == "isPartOf":
                if location_info and obj:
                    sentence_parts.append(f"which is located in {location_info}, part of {obj}")
                else:
                    other_clauses.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                other_clauses.append(f"is operated by {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                other_clauses.append(f"is {obj} metres above sea level")
            elif predicate == "runwayLength":
                other_clauses.append(f"has a runway length of {obj} metres")
            elif predicate == "capital":
                other_clauses.append(f"has {obj} as its capital")
            elif predicate == "language":
                language_info = obj
            elif predicate == "leader":
                other_clauses.append(f"has {obj} as its leader")
            elif predicate == "owner":
                other_clauses.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                other_clauses.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                other_clauses.append(f"has a first runway made of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                other_clauses.append(f"has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                other_clauses.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                other_clauses.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                other_clauses.append(f"is {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                other_clauses.append(f"has an IATA identifier of {obj}")
            elif predicate == "nativeName":
                other_clauses.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                other_clauses.append(f"has {obj} as its governing party")
            elif predicate == "runwayName":
                other_clauses.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                other_clauses.append(f"has a runway made of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                other_clauses.append(f"is {obj} metres above sea level")
            elif predicate == "officialLanguage":
                other_clauses.append(f"has {obj} as its official language")
            elif predicate == "demonym":
                other_clauses.append(f"whose people are called {obj}")
            else:
                other_clauses.append(f"has a {predicate} of {obj}")

    # Build the complex sentence structure
    if location_info and country_info:
        if language_info:
            sentence_parts.append(f"which is located in {location_info}, part of {country_info}, where the language is {language_info}")
        else:
            sentence_parts.append(f"which is located in {location_info}, part of {country_info}")
    elif location_info:
        sentence_parts.append(f"which is located in {location_info}")
    elif country_info:
        sentence_parts.append(f"which is located in {country_info}")

    # Add other clauses
    if other_clauses:
        sentence_parts.append("and " + ", ".join(other_clauses))

    # Join all parts into a single sentence
    result = " ".join(sentence_parts)
    return result + "." if result else "."

